package com.coding.assistant.service;

import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;
import com.coding.assistant.dto.*;
import com.coding.assistant.entity.CodeSnippet;
import com.coding.assistant.entity.LearningRecord;
import com.coding.assistant.exception.BusinessException;
import com.coding.assistant.mapper.CodeSnippetMapper;
import com.coding.assistant.mapper.ConversationMapper;
import com.coding.assistant.mapper.LearningRecordMapper;
import com.itextpdf.text.*;
import com.itextpdf.text.pdf.PdfPCell;
import com.itextpdf.text.pdf.PdfPTable;
import com.itextpdf.text.pdf.PdfWriter;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

import java.io.ByteArrayOutputStream;
import java.time.LocalDate;
import java.time.LocalDateTime;
import java.time.LocalTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

@Slf4j
@Service
@RequiredArgsConstructor
public class ProgressService {

    private final LearningRecordMapper learningRecordMapper;
    private final ConversationMapper conversationMapper;
    private final CodeSnippetMapper codeSnippetMapper;

    @Transactional
    public void recordAction(Long userId, String actionType, String targetId) {
        LearningRecord record = LearningRecord.builder()
                .userId(userId)
                .actionType(actionType)
                .targetId(targetId)
                .createdAt(LocalDateTime.now())
                .build();
        learningRecordMapper.insert(record);
        log.debug("Learning record saved: userId={}, action={}, target={}", userId, actionType, targetId);
    }

    public DashboardVO getDashboard(Long userId) {
        // Total learning days
        int totalDays = learningRecordMapper.countDistinctDaysByUserId(userId);

        // Total chats
        Long totalChats = conversationMapper.selectCount(
                new LambdaQueryWrapper<com.coding.assistant.entity.Conversation>()
                        .eq(com.coding.assistant.entity.Conversation::getUserId, userId)
        );

        // Total snippets
        Long totalSnippets = codeSnippetMapper.selectCount(
                new LambdaQueryWrapper<CodeSnippet>()
                        .eq(CodeSnippet::getUserId, userId)
        );

        // Knowledge coverage (based on distinct action types: chat, code_save, path_learn, graph_explore, feedback)
        List<Map<String, Object>> actionCounts = learningRecordMapper.countByUserIdGroupByActionType(userId);
        double knowledgeCoverage = Math.min(actionCounts.size() * 20.0, 100.0);

        // Recent activity (last 30 days)
        LocalDateTime thirtyDaysAgo = LocalDateTime.now().minusDays(30);
        List<Map<String, Object>> dailyCounts = learningRecordMapper.countByUserIdGroupByDate(
                userId, thirtyDaysAgo, LocalDateTime.now()
        );

        List<ActivityVO> recentActivity = dailyCounts.stream()
                .map(m -> ActivityVO.builder()
                        .date(String.valueOf(m.get("date")))
                        .count(((Number) m.get("count")).intValue())
                        .build())
                .collect(Collectors.toList());

        return DashboardVO.builder()
                .totalDays(totalDays)
                .totalChats(totalChats.intValue())
                .totalSnippets(totalSnippets.intValue())
                .knowledgeCoverage(knowledgeCoverage)
                .recentActivity(recentActivity)
                .build();
    }

    public HeatmapVO getHeatmap(Long userId, int year) {
        LocalDateTime startOfYear = LocalDateTime.of(year, 1, 1, 0, 0);
        LocalDateTime startOfNextYear = LocalDateTime.of(year + 1, 1, 1, 0, 0);

        List<Map<String, Object>> dailyCounts = learningRecordMapper.countByUserIdGroupByDate(
                userId, startOfYear, startOfNextYear
        );

        List<HeatmapDataVO> data = dailyCounts.stream()
                .map(m -> HeatmapDataVO.builder()
                        .date(String.valueOf(m.get("date")))
                        .count(((Number) m.get("count")).intValue())
                        .build())
                .collect(Collectors.toList());

        return HeatmapVO.builder()
                .year(year)
                .data(data)
                .build();
    }

    public RadarVO getRadar(Long userId) {
        List<Map<String, Object>> actionCounts = learningRecordMapper.countByUserIdGroupByActionType(userId);

        List<String> categories = new ArrayList<>();
        List<Double> values = new ArrayList<>();

        // Define standard categories
        String[] standardCategories = {"chat", "code_save", "path_learn", "graph_explore", "feedback"};
        String[] displayNames = {"Chat", "Code Snippets", "Learning Paths", "Graph Exploration", "Feedback"};

        Map<String, Long> countMap = actionCounts.stream()
                .collect(Collectors.toMap(
                        m -> String.valueOf(m.get("action_type")),
                        m -> ((Number) m.get("count")).longValue(),
                        (a, b) -> a
                ));

        double maxCount = countMap.values().stream().mapToLong(Long::longValue).max().orElse(1);

        for (int i = 0; i < standardCategories.length; i++) {
            categories.add(displayNames[i]);
            long count = countMap.getOrDefault(standardCategories[i], 0L);
            values.add(maxCount > 0 ? Math.round(count * 100.0 / maxCount) / 1.0 : 0.0);
        }

        return RadarVO.builder()
                .categories(categories)
                .values(values)
                .build();
    }

    public byte[] generateReport(Long userId) {
        try {
            DashboardVO dashboard = getDashboard(userId);
            HeatmapVO heatmap = getHeatmap(userId, LocalDate.now().getYear());
            RadarVO radar = getRadar(userId);

            ByteArrayOutputStream baos = new ByteArrayOutputStream();
            Document document = new Document(PageSize.A4);
            PdfWriter.getInstance(document, baos);
            document.open();

            // Title
            Font titleFont = new Font(Font.FontFamily.HELVETICA, 24, Font.BOLD, BaseColor.DARK_GRAY);
            Paragraph title = new Paragraph("Learning Progress Report", titleFont);
            title.setAlignment(Element.ALIGN_CENTER);
            title.setSpacingAfter(20);
            document.add(title);

            // Date
            Font dateFont = new Font(Font.FontFamily.HELVETICA, 12, Font.NORMAL, BaseColor.GRAY);
            Paragraph date = new Paragraph("Generated: " + LocalDate.now().format(DateTimeFormatter.ISO_LOCAL_DATE), dateFont);
            date.setAlignment(Element.ALIGN_CENTER);
            date.setSpacingAfter(30);
            document.add(date);

            // Overview Section
            Font sectionFont = new Font(Font.FontFamily.HELVETICA, 16, Font.BOLD, BaseColor.DARK_GRAY);
            Paragraph overviewTitle = new Paragraph("Overview", sectionFont);
            overviewTitle.setSpacingAfter(10);
            document.add(overviewTitle);

            // Stats table
            PdfPTable statsTable = new PdfPTable(2);
            statsTable.setWidthPercentage(80);
            statsTable.setSpacingAfter(20);

            Font cellFont = new Font(Font.FontFamily.HELVETICA, 12, Font.NORMAL);
            Font valuFont = new Font(Font.FontFamily.HELVETICA, 12, Font.BOLD);

            addTableRow(statsTable, "Total Learning Days", String.valueOf(dashboard.getTotalDays()), cellFont, valuFont);
            addTableRow(statsTable, "Total Conversations", String.valueOf(dashboard.getTotalChats()), cellFont, valuFont);
            addTableRow(statsTable, "Total Code Snippets", String.valueOf(dashboard.getTotalSnippets()), cellFont, valuFont);
            addTableRow(statsTable, "Knowledge Coverage", String.format("%.1f%%", dashboard.getKnowledgeCoverage()), cellFont, valuFont);

            document.add(statsTable);

            // Activity Distribution
            Paragraph radarTitle = new Paragraph("Activity Distribution", sectionFont);
            radarTitle.setSpacingAfter(10);
            document.add(radarTitle);

            PdfPTable radarTable = new PdfPTable(2);
            radarTable.setWidthPercentage(80);
            radarTable.setSpacingAfter(20);

            for (int i = 0; i < radar.getCategories().size(); i++) {
                addTableRow(radarTable, radar.getCategories().get(i),
                        String.format("%.0f%%", radar.getValues().get(i)), cellFont, valuFont);
            }
            document.add(radarTable);

            // Recent Activity
            if (!dashboard.getRecentActivity().isEmpty()) {
                Paragraph activityTitle = new Paragraph("Recent Activity (Last 30 Days)", sectionFont);
                activityTitle.setSpacingAfter(10);
                document.add(activityTitle);

                PdfPTable activityTable = new PdfPTable(2);
                activityTable.setWidthPercentage(80);
                activityTable.setSpacingAfter(20);

                for (ActivityVO activity : dashboard.getRecentActivity()) {
                    addTableRow(activityTable, activity.getDate(),
                            activity.getCount() + " activities", cellFont, valuFont);
                }
                document.add(activityTable);
            }

            document.close();
            return baos.toByteArray();
        } catch (DocumentException e) {
            log.error("Error generating PDF report: {}", e.getMessage());
            throw new BusinessException(500, "Failed to generate report");
        }
    }

    private void addTableRow(PdfPTable table, String label, String value, Font labelFont, Font valueFont) {
        PdfPCell labelCell = new PdfPCell(new Phrase(label, labelFont));
        labelCell.setBorderColor(BaseColor.LIGHT_GRAY);
        labelCell.setPadding(8);
        table.addCell(labelCell);

        PdfPCell valueCell = new PdfPCell(new Phrase(value, valueFont));
        valueCell.setBorderColor(BaseColor.LIGHT_GRAY);
        valueCell.setPadding(8);
        valueCell.setHorizontalAlignment(Element.ALIGN_RIGHT);
        table.addCell(valueCell);
    }
}
